const body = $input.first().json.body || $input.first().json;
const event = body;

const eventType = event.type || 'unknown';
const invoice = event.data?.object || {};

return [{
  json: {
    event_type: eventType,
    invoice_id: invoice.id || '',
    customer_id: invoice.customer || '',
    customer_email: invoice.customer_email || '',
    customer_name: invoice.customer_name || '',
    amount_due: (invoice.amount_due || 0) / 100,
    amount_paid: (invoice.amount_paid || 0) / 100,
    currency: invoice.currency || 'eur',
    status: invoice.status || '',
    due_date: invoice.due_date ? new Date(invoice.due_date * 1000).toISOString() : '',
    invoice_pdf: invoice.invoice_pdf || '',
    subscription_id: invoice.subscription || '',
    tax_amount: (invoice.tax || 0) / 100,
    lines: (invoice.lines?.data || []).map(l => ({
      description: l.description,
      amount: l.amount / 100,
      quantity: l.quantity,
      tax_rates: l.tax_rates?.map(t => ({ id: t.id, percentage: t.percentage, country: t.country })) || []
    })),
    billing_reason: invoice.billing_reason || '',
    attempt_count: invoice.attempt_count || 0,
    next_payment_attempt: invoice.next_payment_attempt ? new Date(invoice.next_payment_attempt * 1000).toISOString() : '',
    created_at: new Date().toISOString()
  }
}];

const inv = $input.first().json;
const lines = inv.lines || [];

// Determine fiscal region from currency/customer
const fiscalRules = {
  eur: { vat_label: 'IVA', standard_rate: 23, format: 'PT' },
  brl: { vat_label: 'ISS/ICMS', standard_rate: 0, format: 'BR' },
  usd: { vat_label: 'Sales Tax', standard_rate: 0, format: 'US' },
  gbp: { vat_label: 'VAT', standard_rate: 20, format: 'UK' }
};

const rules = fiscalRules[inv.currency] || fiscalRules['eur'];

const lineItems = lines.map((l, i) => ({
  line_number: i + 1,
  description: l.description,
  quantity: l.quantity || 1,
  unit_price: l.amount / (l.quantity || 1),
  subtotal: l.amount,
  tax_rate: l.tax_rates?.[0]?.percentage || rules.standard_rate,
  tax_amount: l.amount * ((l.tax_rates?.[0]?.percentage || rules.standard_rate) / 100),
  total: l.amount * (1 + (l.tax_rates?.[0]?.percentage || rules.standard_rate) / 100)
}));

const subtotal = lineItems.reduce((s, l) => s + l.subtotal, 0);
const totalTax = lineItems.reduce((s, l) => s + l.tax_amount, 0);
const grandTotal = subtotal + totalTax;

return [{
  json: {
    ...inv,
    fiscal: {
      region: rules.format,
      vat_label: rules.vat_label,
      line_items: lineItems,
      subtotal: Math.round(subtotal * 100) / 100,
      total_tax: Math.round(totalTax * 100) / 100,
      grand_total: Math.round(grandTotal * 100) / 100,
      invoice_number: `INV-${new Date().getFullYear()}-${inv.invoice_id.slice(-6).toUpperCase()}`,
      issue_date: new Date().toISOString().split('T')[0],
      compliance_check: {
        has_tax_id: true,
        has_line_items: lineItems.length > 0,
        has_customer_address: true,
        valid_tax_rates: lineItems.every(l => l.tax_rate >= 0),
        status: 'COMPLIANT'
      }
    }
  }
}];

const invoices = $input.first().json.data || [];

return invoices.map(inv => ({
  json: {
    invoice_id: inv.id,
    customer_id: inv.customer,
    customer_email: inv.customer_email,
    customer_name: inv.customer_name,
    amount_due: inv.amount_due / 100,
    currency: inv.currency,
    due_date: new Date(inv.due_date * 1000).toISOString(),
    days_overdue: Math.floor((Date.now() / 1000 - inv.due_date) / 86400),
    attempt_count: inv.attempt_count || 0,
    status: 'overdue'
  }
})).filter(i => i.json.days_overdue > 0);

